const item = $input.first();
const cfg = item.json;

// El archivo de Infra llega como binario; lo pasamos a texto para parsear línea por línea
const buffer = item
const text = buffer.toString('utf8') || "test";

const lines = text.split(/\r?\n/).filter(l => l.trim() !== '');

// Formato esperado por línea (ver docx "Validación tamaño RPT por ambiente"):
// <KB> <ruta>\\<version>\\<nombre>.rpt
// Ej: 992 D:\\COMFIAR_PE\\Directorios\\Reportes\\AFP-FA\\1\\AFP-FA.rpt
const seen = new Set();
const matches = [];

for (const line of lines) {
  const m = line.trim().match(/^(\d+)\s+(.+)$/);
  if (!m) continue;

  const kb = parseInt(m[1], 10);
  if (kb <= 500) continue; // solo RPT > 500 KB

  const parts = m[2].split('\\');
  if (parts.length < 2) continue;

  const version = parts[parts.length - 2];
  const nombreRpt = parts[parts.length - 1];
  const key = `${nombreRpt}|${version}`;

  if (seen.has(key)) continue;
  seen.add(key);

  matches.push({ nombreRpt, version: parseInt(version, 10), kb });
}

return [{
  json: {
    ...cfg,
    matches,
    hasMatches: matches.length > 0
  }
}];

const sql = require('mssql');

const item = $input.first().json;

const valuesClause = item.matches
  .map(m => `('${m.nombreRpt.replace(/'/g, "''")}', ${m.version})`)
  .join(',\n        ');

const query = `
SELECT c.CuitId, c.RazonSocial, t.PuntoDeVentaId, t.TipoComprobanteId, t.VersionRpt, t.NombreRpt, a.FechaSubida, a.UsuarioId
FROM TipoComprobanteXPuntoDeVenta t
INNER JOIN VersionReporte a ON t.VersionRpt = a.VersionId AND t.NombreRpt = a.NombreRpt
INNER JOIN Cuit c ON t.CuitId = c.CuitId
INNER JOIN (VALUES
        ${valuesClause}
) v(NombreRpt, VersionId) ON a.NombreRpt = v.NombreRpt AND a.VersionId = v.VersionId
WHERE c.FechaBajaServicio IS NULL;
`;

const config = {
  server: item.dbHost,
  port: item.dbPort,
  database: item.dbName,
  user: item.dbUser,
  password: item.dbPassword,
  options: {
    trustServerCertificate: true,
    encrypt: false
  }
};

let results = [];
const pool = await sql.connect(config);
try {
  const res = await pool.request().query(query);
  results = res.recordset;
} finally {
  await pool.close();
}

return [{
  json: {
    ...item,
    results,
    hasResults: results.length > 0
  }
}];

